import type { SubmitEvent } from "react";
import { useState } from "react";

import type { DynamicNotificationProps, OpenChangeEventDetails, OpenChangeReason } from "../contracts";

// Hand-built (no Base UI primitive backs the island) but shaped exactly like Base UI's details so
// callers get the one onOpenChange contract used across every popup-style component (contracts.ts).
function createOpenChangeEventDetails(reason: OpenChangeReason, event: Event, trigger: Element | undefined): OpenChangeEventDetails {
  let canceled = false;
  let propagationAllowed = false;
  return {
    reason,
    event,
    cancel() {
      canceled = true;
    },
    allowPropagation() {
      propagationAllowed = true;
    },
    get isCanceled() {
      return canceled;
    },
    get isPropagationAllowed() {
      return propagationAllowed;
    },
    trigger,
  };
}

function useControllableText({
  value,
  defaultValue = "",
  onValueChange,
}: {
  value?: string;
  defaultValue?: string;
  onValueChange?: (value: string) => void;
}) {
  const [internalValue, setInternalValue] = useState(defaultValue);
  const isControlled = value !== undefined;
  const currentValue = isControlled ? value : internalValue;

  function setValue(nextValue: string) {
    if (!isControlled) setInternalValue(nextValue);
    onValueChange?.(nextValue);
  }

  return [currentValue, setValue] as const;
}

export function useDynamicNotification({
  open,
  defaultOpen = false,
  onOpenChange,
  replyValue,
  defaultReplyValue,
  onReplyValueChange,
  onReply,
  disabled = false,
}: Pick<
  DynamicNotificationProps,
  "open" | "defaultOpen" | "onOpenChange" | "replyValue" | "defaultReplyValue" | "onReplyValueChange" | "onReply" | "disabled"
>) {
  const [internalOpen, setInternalOpen] = useState(defaultOpen);
  const isControlled = open !== undefined;
  const isOpen = isControlled ? open : internalOpen;

  const [reply, setReply] = useControllableText({
    value: replyValue,
    defaultValue: defaultReplyValue,
    onValueChange: onReplyValueChange,
  });
  const normalizedReply = reply.trim();
  const canSubmit = normalizedReply.length > 0 && !disabled;

  function setOpen(nextOpen: boolean, reason: OpenChangeReason, event: Event, trigger?: Element) {
    if (disabled || nextOpen === isOpen) return;
    const details = createOpenChangeEventDetails(reason, event, trigger);
    onOpenChange?.(nextOpen, details);
    if (details.isCanceled) return;
    if (!isControlled) setInternalOpen(nextOpen);
  }

  function clear() {
    setReply("");
  }

  function submitReply() {
    if (!canSubmit) return;
    void onReply?.({ value: normalizedReply, clear });
  }

  function handleReplySubmit(event: SubmitEvent<HTMLFormElement>) {
    event.preventDefault();
    submitReply();
  }

  return {
    open: isOpen,
    disabled,
    setOpen,
    reply,
    setReply,
    normalizedReply,
    canSubmit,
    clear,
    submitReply,
    handleReplySubmit,
  };
}

import { DYNAMIC_NOTIFICATION_SIRI_WAVE_GLSL } from "@/components/control-ui/dynamic-notification-siri-wave";

/*
 * Liquid-glass WebGL material for DynamicNotification's "glass" variant (Siri-style island).
 * Vanilla engine (no React): the component hands it one <canvas>, it returns a single cleanup fn —
 * same split as extensions/create-track-highlight.ts. CSS keeps a gradient fallback under the canvas,
 * so no WebGL (or a lost context) degrades to the static material instead of a hole.
 * Paints: black→glass vertical gradient, top sheen with slight spectral dispersion, a chromatic
 * Siri waveform across the horizon, and an inner rim light — all inside a
 * rounded-rect SDF matching the island's current border-radius (re-read per frame so the
 * pill→bubble morph stays in sync).
 * Reduced motion (OS media query or data-motion="reduced"): renders exactly one static frame,
 * re-rendering only on geometry changes — never a running RAF loop.
 */

export type DynamicNotificationGlassOptions = {
  /** Aurora strength 0..1 (default 1). */
  intensity?: number;
  /** devicePixelRatio clamp (default 2) — the island is small, 2x is visually lossless. */
  maxDpr?: number;
};

const VERTEX_SHADER = /* glsl */ `
attribute vec2 a_position;
void main() {
  gl_Position = vec4(a_position, 0.0, 1.0);
}
`;

const FRAGMENT_SHADER = /* glsl */ `
precision highp float;

uniform vec2 u_resolution;
uniform float u_time;
uniform float u_radius;
uniform float u_intensity;
uniform float u_aurora;
uniform float u_reveal;
uniform float u_settle;
uniform float u_lift;
uniform float u_ribbonHorizon;

float sdRoundBox(vec2 p, vec2 b, float r) {
  vec2 q = abs(p) - b + r;
  return length(max(q, 0.0)) + min(max(q.x, q.y), 0.0) - r;
}

float hash(vec2 p) {
  return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453);
}

float ridge(float y, float center, float sharpness) {
  float delta = (y - center) * sharpness;
  return exp(-delta * delta);
}

${DYNAMIC_NOTIFICATION_SIRI_WAVE_GLSL}

void main() {
  vec2 uv = gl_FragCoord.xy / u_resolution;
  vec2 p = gl_FragCoord.xy - 0.5 * u_resolution;
  vec2 halfSize = 0.5 * u_resolution;
  float radius = min(u_radius, min(halfSize.x, halfSize.y));
  float d = sdRoundBox(p, halfSize, radius);
  float shape = 1.0 - smoothstep(-1.5, 0.5, d);
  if (shape <= 0.0) {
    gl_FragColor = vec4(0.0);
    return;
  }

  /* 1. ink profile: a SOLID black face while collapsed that dissolves into the REAL
     black -> 10% black gradient as u_reveal eases toward 1 (thinking + expanded) — the
     gradient itself morphs, so the pill never pops from opaque to translucent */
  /* Two plateau curves, blended by u_settle so the bubble's ink thickens on the same spring that
     opens it. The thinking fade is centred on the ribbon horizon; expanded keeps a 0.4 floor for
     the reply controls in its bottom third. */
  float gradThinking = mix(0.10, 0.97, smoothstep(u_ribbonHorizon - 0.10, u_ribbonHorizon + 0.10, uv.y));
  float gradExpanded = mix(0.40, 0.97, smoothstep(0.00, 0.30, uv.y));
  float grad = mix(gradThinking, gradExpanded, u_settle);
  float alpha = mix(0.97, grad, u_reveal);
  vec3 color = vec3(0.004, 0.004, 0.006) * mix(1.0, 0.4 + 0.6 * uv.y, u_reveal);

  /* 2. sheen horizon with subtle spectral dispersion (the pale rainbow band on the real island) */
  float sheenY = u_ribbonHorizon + 0.02 * sin(u_time * 0.35);
  float sheen = ridge(uv.y, sheenY, 9.0);
  float spread = smoothstep(0.06, 0.4, uv.x) * smoothstep(0.94, 0.6, uv.x);
  color += spread * 0.085 * vec3(
    sheen * (0.9 + 0.35 * sin(uv.x * 8.0 + 1.6)),
    ridge(uv.y, sheenY + 0.015, 9.5),
    ridge(uv.y, sheenY - 0.02, 8.5) * 1.15
  );

  vec3 aurora = dynamicNotificationSiriWave(uv, u_resolution, u_time, u_ribbonHorizon, u_lift)
    * u_intensity * u_aurora * (1.0 - u_lift);
  float glow = max(aurora.r, max(aurora.g, aurora.b));
  alpha = min(1.0, alpha + glow * 0.5);

  /* 3. inner rim light — glass thickness catching the environment */
  float rim = exp(-pow((d + 1.75) * 0.30, 2.0));
  color += rim * vec3(0.82, 0.88, 1.0) * (0.05 + 0.10 * (1.0 - uv.y));

  /* 4. edge refraction of the glass container itself: a THIN ring where the ink barely thins
     so a hint of the CSS-blurred backdrop shows through, with a dark seam just inside and a
     bright pull at the top. Kept narrow and mostly opaque on purpose: a wide translucent band
     under the backdrop blur reads as the background melting into the edge, not as glass. */
  float bevelW = max(4.0, u_radius * 0.32);
  float bt = clamp(1.0 + d / bevelW, 0.0, 1.0);
  float bevel = pow(bt, 2.4);
  alpha *= 1.0 - 0.30 * bevel;
  float seam = exp(-pow((bt - 0.42) * 7.0, 2.0));
  color *= 1.0 - 0.25 * seam;
  color += vec3(0.95, 0.97, 1.0) * bevel * bevel * (0.35 + 0.65 * uv.y) * 0.18;

  /* dither so the long dark gradient never bands */
  color += (hash(gl_FragCoord.xy) - 0.5) / 255.0;

  alpha *= shape;
  gl_FragColor = vec4(color * alpha + aurora * shape, alpha);
}
`;

type GlassProgram = {
  program: WebGLProgram;
  buffer: WebGLBuffer;
  resolution: WebGLUniformLocation | null;
  time: WebGLUniformLocation | null;
  radius: WebGLUniformLocation | null;
  intensity: WebGLUniformLocation | null;
  aurora: WebGLUniformLocation | null;
  reveal: WebGLUniformLocation | null;
  settle: WebGLUniformLocation | null;
  lift: WebGLUniformLocation | null;
  ribbonHorizon: WebGLUniformLocation | null;
};

function compileShader(gl: WebGLRenderingContext, type: number, source: string): WebGLShader | null {
  const shader = gl.createShader(type);
  if (!shader) return null;
  gl.shaderSource(shader, source);
  gl.compileShader(shader);
  if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
    gl.deleteShader(shader);
    return null;
  }
  return shader;
}

function buildProgram(gl: WebGLRenderingContext): GlassProgram | null {
  const vertex = compileShader(gl, gl.VERTEX_SHADER, VERTEX_SHADER);
  const fragment = compileShader(gl, gl.FRAGMENT_SHADER, FRAGMENT_SHADER);
  if (!vertex || !fragment) return null;
  const program = gl.createProgram();
  const buffer = gl.createBuffer();
  if (!program || !buffer) return null;
  gl.attachShader(program, vertex);
  gl.attachShader(program, fragment);
  gl.linkProgram(program);
  gl.deleteShader(vertex);
  gl.deleteShader(fragment);
  if (!gl.getProgramParameter(program, gl.LINK_STATUS)) return null;

  gl.bindBuffer(gl.ARRAY_BUFFER, buffer);
  gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([-1, -1, 1, -1, -1, 1, 1, 1]), gl.STATIC_DRAW);
  const position = gl.getAttribLocation(program, "a_position");
  gl.enableVertexAttribArray(position);
  gl.vertexAttribPointer(position, 2, gl.FLOAT, false, 0, 0);

  return {
    program,
    buffer,
    resolution: gl.getUniformLocation(program, "u_resolution"),
    time: gl.getUniformLocation(program, "u_time"),
    radius: gl.getUniformLocation(program, "u_radius"),
    intensity: gl.getUniformLocation(program, "u_intensity"),
    aurora: gl.getUniformLocation(program, "u_aurora"),
    reveal: gl.getUniformLocation(program, "u_reveal"),
    settle: gl.getUniformLocation(program, "u_settle"),
    lift: gl.getUniformLocation(program, "u_lift"),
    ribbonHorizon: gl.getUniformLocation(program, "u_ribbonHorizon"),
  };
}

/* aurora shows ONLY while the model is thinking; the static pill and the opened chat stay clean */
function auroraTarget(state: string | undefined): number {
  return state === "thinking" ? 1 : 0;
}

/* gradient reveal: only the collapsed pill is solid black; the thinking blob and the expanded
   bubble both show the black -> transparent fade */
function revealTarget(state: string | undefined): number {
  return state === "collapsed" ? 0 : 1;
}

/* which of the two ink ramps the fade lands on: the thinking blob runs out to transparent, the
   expanded bubble keeps a floor so its reply controls have something to sit on */
function settleTarget(state: string | undefined): number {
  return state === "expanded" ? 1 : 0;
}

export function createDynamicNotificationGlass(canvas: HTMLCanvasElement, options: DynamicNotificationGlassOptions = {}): () => void {
  const { intensity = 1, maxDpr = 2 } = options;
  const gl = canvas.getContext("webgl", { alpha: true, premultipliedAlpha: true, antialias: true });
  if (!gl) return () => {};

  // Remount on the same canvas (StrictMode double-effect, fast skin swaps) hands back the SAME
  // live context — which is why cleanup only deletes program+buffer and NEVER loseContext():
  // a lose()d context can't hand out WEBGL_lose_context anymore (getExtension returns null when
  // lost), so no later instance could ever restore it. The context's real lifetime is the canvas's.
  let contextLost = gl.isContextLost();
  let glass = contextLost ? null : buildProgram(gl);
  if (!contextLost && !glass) return () => {};

  let destroyed = false;
  let intersecting = true;
  let pageVisible = !document.hidden;
  let rafId = 0;
  let dpr = 1;
  /* radius eases toward the island's live border-radius so the shader rim follows the pill→bubble morph */
  let radius = 0;
  /* aurora energy eases toward the island's data-state target (thinking pulses, expanded settles) */
  let aurora = auroraTarget(canvas.parentElement?.dataset.state);
  /* lift sends the dying sheet toward the top on exit; parked high whenever the aurora is off */
  let lift = 1 - aurora;
  let reveal = revealTarget(canvas.parentElement?.dataset.state);
  let settle = settleTarget(canvas.parentElement?.dataset.state);
  let staticFrameDrawn = false;
  const startedAt = performance.now();
  const reducedMotionQuery = window.matchMedia("(prefers-reduced-motion: reduce)");

  function reducedMotion(): boolean {
    return reducedMotionQuery.matches || canvas.closest('[data-motion="reduced"]') !== null;
  }

  function targetRadius(): number {
    const host = canvas.parentElement;
    if (!host) return 0;
    const parsed = Number.parseFloat(getComputedStyle(host).borderTopLeftRadius);
    return Number.isFinite(parsed) ? parsed * dpr : 0;
  }

  function targetRibbonHorizon(): number {
    const host = canvas.parentElement;
    if (!host) return 0.5;
    const parsed = Number.parseFloat(getComputedStyle(host).getPropertyValue("--dn-ribbon-horizon"));
    return Number.isFinite(parsed) ? Math.min(1, Math.max(0, parsed / 100)) : 0.5;
  }

  /* Runs at the TOP of every draw, never from observers: setting canvas.width clears the buffer,
     so resize and repaint must share one task or the compositor shows a blank frame (flicker —
     rAF ticks run BEFORE ResizeObserver callbacks within a frame, so an observer-side resize
     wiped the freshly drawn pixels right before paint on every morph frame). */
  function resize(): void {
    // clientWidth/Height: layout box, immune to the @starting-style scale running at mount
    // (getBoundingClientRect would bake the mid-animation transform into the backing size).
    dpr = Math.min(window.devicePixelRatio || 1, maxDpr);
    const width = Math.max(1, Math.round(canvas.clientWidth * dpr));
    const height = Math.max(1, Math.round(canvas.clientHeight * dpr));
    if (canvas.width !== width || canvas.height !== height) {
      canvas.width = width;
      canvas.height = height;
    }
  }

  function advanceMotion(reduced: boolean): void {
    const target = targetRadius();
    radius = reduced ? target : radius + (target - radius) * 0.25;

    const auroraGoal = auroraTarget(canvas.parentElement?.dataset.state);
    aurora = reduced ? auroraGoal : aurora + (auroraGoal - aurora) * 0.06;
    /* Keep exit linear so the sheet clears the surface before the opening morph collapses. */
    const liftGoal = auroraGoal >= 0.5 ? 0 : 1;
    if (reduced) lift = liftGoal;
    else if (liftGoal === 1) lift = Math.min(1, lift + 0.036);
    else lift *= 0.72;

    const revealGoal = revealTarget(canvas.parentElement?.dataset.state);
    reveal = reduced ? revealGoal : reveal + (revealGoal - reveal) * 0.07;
    const settleGoal = settleTarget(canvas.parentElement?.dataset.state);
    settle = reduced ? settleGoal : settle + (settleGoal - settle) * 0.07;
  }

  function uploadUniforms(activeGl: WebGLRenderingContext, activeGlass: GlassProgram, reduced: boolean): void {
    activeGl.uniform2f(activeGlass.resolution, canvas.width, canvas.height);
    activeGl.uniform1f(activeGlass.time, reduced ? 4.2 : (performance.now() - startedAt) / 1000);
    activeGl.uniform1f(activeGlass.radius, radius);
    activeGl.uniform1f(activeGlass.intensity, intensity);
    activeGl.uniform1f(activeGlass.aurora, aurora);
    activeGl.uniform1f(activeGlass.reveal, reveal);
    activeGl.uniform1f(activeGlass.settle, settle);
    activeGl.uniform1f(activeGlass.lift, lift);
    activeGl.uniform1f(activeGlass.ribbonHorizon, targetRibbonHorizon());
  }

  function draw(): void {
    if (!gl || !glass || contextLost) return;
    resize();
    gl.viewport(0, 0, canvas.width, canvas.height);
    gl.clearColor(0, 0, 0, 0);
    gl.clear(gl.COLOR_BUFFER_BIT);
    // biome-ignore lint/correctness/useHookAtTopLevel: WebGL's useProgram, not a React hook.
    gl.useProgram(glass.program);
    const reduced = reducedMotion();
    advanceMotion(reduced);
    uploadUniforms(gl, glass, reduced);
    gl.drawArrays(gl.TRIANGLE_STRIP, 0, 4);
    if (canvas.dataset.glassReady !== "true") canvas.dataset.glassReady = "true";
  }

  function visible(): boolean {
    return intersecting && pageVisible;
  }

  function tick(): void {
    rafId = 0;
    if (destroyed || !visible() || contextLost) return;
    draw();
    if (reducedMotion()) {
      staticFrameDrawn = true;
      return;
    }
    staticFrameDrawn = false;
    rafId = requestAnimationFrame(tick);
  }

  /* single entry point: (re)starts the loop, or repaints the one static frame in reduced motion */
  function invalidate(): void {
    staticFrameDrawn = false;
    if (destroyed || !visible() || contextLost || rafId !== 0) return;
    rafId = requestAnimationFrame(tick);
  }

  function handleVisibility(): void {
    pageVisible = !document.hidden;
    invalidate();
  }

  function handleContextLost(event: Event): void {
    // preventDefault signals we want the context back; the browser then fires webglcontextrestored.
    event.preventDefault();
    contextLost = true;
    if (rafId !== 0) cancelAnimationFrame(rafId);
    rafId = 0;
  }

  function handleContextRestored(): void {
    // hoisted declaration: re-narrow gl locally (the outer guard's narrowing doesn't flow in)
    if (!gl) return;
    contextLost = false;
    glass = buildProgram(gl);
    invalidate();
  }

  /* observers only INVALIDATE — the actual buffer resize happens inside draw() (see resize) */
  const resizeObserver = new ResizeObserver(() => {
    invalidate();
  });
  resizeObserver.observe(canvas);

  /* pause offscreen (previews below the fold, background tabs keep GPU idle) */
  const intersectionObserver = new IntersectionObserver(
    (entries) => {
      for (const entry of entries) intersecting = entry.isIntersecting;
      invalidate();
    },
    { rootMargin: "64px" },
  );
  intersectionObserver.observe(canvas);

  /* the docs theme editor toggles data-motion on <html> live; repaint (or restart) when it flips */
  const motionObserver = new MutationObserver(() => {
    if (!staticFrameDrawn || !reducedMotion()) invalidate();
  });
  motionObserver.observe(document.documentElement, { attributes: true, attributeFilter: ["data-motion"] });

  function handleMotionPreference(): void {
    invalidate();
  }

  document.addEventListener("visibilitychange", handleVisibility);
  reducedMotionQuery.addEventListener("change", handleMotionPreference);
  canvas.addEventListener("webglcontextlost", handleContextLost);
  canvas.addEventListener("webglcontextrestored", handleContextRestored);

  invalidate();

  return () => {
    destroyed = true;
    if (rafId !== 0) cancelAnimationFrame(rafId);
    resizeObserver.disconnect();
    intersectionObserver.disconnect();
    motionObserver.disconnect();
    document.removeEventListener("visibilitychange", handleVisibility);
    reducedMotionQuery.removeEventListener("change", handleMotionPreference);
    canvas.removeEventListener("webglcontextlost", handleContextLost);
    canvas.removeEventListener("webglcontextrestored", handleContextRestored);
    delete canvas.dataset.glassReady;
    if (glass && !gl.isContextLost()) {
      gl.deleteProgram(glass.program);
      gl.deleteBuffer(glass.buffer);
    }
    glass = null;
  };
}

import { DYNAMIC_NOTIFICATION_SIRI_WAVE_GLSL } from "@/components/control-ui/dynamic-notification-siri-wave";
import { LIQUID_GLASS_OPTICS_GLSL } from "@/components/control-ui/lib/liquid-glass-optics";

/* Keep full-surface transmission separate from the narrow edge-light field so refraction stays visible without a halo. */

export type DynamicNotificationLiquidOptions = {
  /** Virtual lens depth (default 0.85) applied to the size-derived inner edge profile. */
  refraction?: number;
  /** Chromatic aberration (default 0) — optional RGB separation; Apple does not expose it as a material property. */
  chromaticAberration?: number;
  /** Inner refraction band cap in css px (default 32). */
  zRadius?: number;
  /** Directional dark edge intensity (default 0.05). */
  edgeDarkening?: number;
  /** Opposed perimeter highlight intensity (default 0.11). */
  specular?: number;
  /** Grazing reflection intensity (default 0.35). */
  fresnel?: number;
  /** Edge highlight intensity (default 0.16). */
  edgeHighlight?: number;
  /** Frost factor for shader-native diffusion (default 4). The centre remains sharp-dominant. */
  frost?: number;
  /** devicePixelRatio clamp (default 2). */
  maxDpr?: number;
};

const VERTEX_SHADER = /* glsl */ `
attribute vec2 a_position;
varying vec2 v_uv;
void main() {
  /* v_uv is y-DOWN (v=0 = top) to match the 2D-canvas texture orientation */
  v_uv = vec2(a_position.x * 0.5 + 0.5, 0.5 - a_position.y * 0.5);
  gl_Position = vec4(a_position, 0.0, 1.0);
}
`;

/* The optical field runs in css px with a y-down local frame centred on the panel. */
const FRAGMENT_SHADER = /* glsl */ `
precision highp float;

uniform sampler2D u_sharpTex;
uniform sampler2D u_blurTex;
uniform vec2 u_size;        /* panel size, css px */
uniform vec2 u_panelOffset; /* panel top-left inside the scene, css px */
uniform vec2 u_sceneSize;   /* scene size, css px */
uniform float u_radius;     /* corner radius, css px */
uniform float u_zRadius;    /* inner refraction band cap, css px */
uniform float u_refract;
uniform float u_chroma;
uniform float u_edgeDarkening;
uniform float u_spec;
uniform float u_fresnel;
uniform float u_edgeHL;
uniform float u_time;
uniform float u_aurora;
uniform float u_reveal;
uniform float u_settle;
uniform float u_lift;
uniform float u_ribbonHorizon;

varying vec2 v_uv;

${LIQUID_GLASS_OPTICS_GLSL}
${DYNAMIC_NOTIFICATION_SIRI_WAVE_GLSL}

vec2 sceneUV(vec2 posCss) {
  return clamp(posCss / u_sceneSize, 0.0, 1.0);
}

void main() {
  vec2 local = (v_uv - 0.5) * u_size;
  vec2 half_ = u_size * 0.5;
  float r = min(u_radius, min(half_.x, half_.y));
  float sdf = liquidSurfaceSDF(local, half_, r, 2.0);

  /* The mask clips only the shape; resting Clear material has no separate shadow stage. */
  float mask = 1.0 - smoothstep(-1.5, 0.5, sdf);
  if (mask <= 0.0) {
    gl_FragColor = vec4(0.0);
    return;
  }

  float materialScale = smoothstep(40.0, 120.0, u_size.y);
  float edgeWidth = liquidEdgeWidth(u_size, 0.36, u_zRadius);
  float opticalInside = liquidOpticalInsideDistance(local, half_, r, 2.0);
  float lens = liquidEdgeLens(opticalInside, edgeWidth);
  vec2 boundaryNormal = liquidInwardOpticalNormal(local, half_, r, 2.0);

  vec2 refrPx = liquidRefractedOffset(boundaryNormal, opticalInside, edgeWidth, u_refract);
  vec3 N = liquidLensSurfaceNormal(boundaryNormal, opticalInside, edgeWidth);
  vec2 keyDirection = normalize(vec2(0.707106, -0.707106));
  float outerRim = 1.0 - smoothstep(0.35, 1.35, opticalInside);
  float innerRim = exp(-pow((opticalInside - 2.0) / 0.9, 2.0));

  float caS = u_chroma * 10.0 * lens;
  vec2 caD = N.xy * caS;
  vec2 base = u_panelOffset + v_uv * u_size + refrPx;

  vec3 sharp = vec3(
    texture2D(u_sharpTex, sceneUV(base + caD)).r,
    texture2D(u_sharpTex, sceneUV(base)).g,
    texture2D(u_sharpTex, sceneUV(base - caD)).b
  );
  vec3 blur = vec3(
    texture2D(u_blurTex, sceneUV(base + caD)).r,
    texture2D(u_blurTex, sceneUV(base)).g,
    texture2D(u_blurTex, sceneUV(base - caD)).b
  );
  float diffusion = mix(0.08, 0.14, materialScale) * mix(0.25, 1.0, lens);
  vec3 col = mix(sharp, blur, diffusion);

  /* Map transmitted luminance to the measured Clear-material endpoints while preserving hue. */
  float transmittedLuma = dot(col, vec3(0.2126, 0.7152, 0.0722));
  float environmentLuma = dot(blur, vec3(0.2126, 0.7152, 0.0722));
  float lightEnvironment = smoothstep(0.38, 0.72, environmentLuma);
  float blackEndpoint = mix(0.05, 0.20, lightEnvironment);
  float whiteEndpoint = mix(0.80, 0.95, lightEnvironment);
  float mappedLuma = mix(blackEndpoint, whiteEndpoint, transmittedLuma);
  col = clamp(col + vec3(mappedLuma - transmittedLuma), 0.0, 1.0);

  /* Ink and ribbon share the refracted coordinate so their horizon stays joined at the edges. */
  vec2 auroraUv = clamp(v_uv + N.xy * lens * 0.012, vec2(0.0), vec2(1.0));
  float yUp = 1.0 - auroraUv.y;
  float inkThinking = mix(0.10, 0.985, smoothstep(u_ribbonHorizon - 0.10, u_ribbonHorizon + 0.10, yUp));
  float inkExpanded = mix(0.24, 0.97, smoothstep(0.00, 0.30, yUp));
  float ink = mix(0.985, mix(inkThinking, inkExpanded, u_settle), u_reveal);
  vec3 materialColor = mix(col, vec3(0.004, 0.004, 0.006), ink);

  float keyArc = pow(max(dot(boundaryNormal, keyDirection), 0.0), 6.0);
  float fillArc = pow(max(dot(boundaryNormal, -keyDirection), 0.0), 8.0) * 0.28;
  float shadowArc = pow(max(dot(boundaryNormal, -keyDirection), 0.0), 6.0);
  materialColor *= 1.0 - innerRim * shadowArc * u_edgeDarkening;
  float highlight = outerRim * u_edgeHL * 0.22 + innerRim * (keyArc * u_spec + fillArc * u_spec * 1.3);
  float grazing = outerRim * u_fresnel * 0.025;
  vec3 rimLight = mix(vec3(1.0), blur, 0.12);

  vec3 auroraEmission = dynamicNotificationSiriWave(vec2(auroraUv.x, yUp), u_size, u_time, u_ribbonHorizon, u_lift)
    * u_aurora * (1.0 - u_lift);

  vec3 material = materialColor + rimLight * highlight + vec3(grazing) + auroraEmission;
  gl_FragColor = vec4(material * mask, mask);
}
`;

type LiquidProgram = {
  program: WebGLProgram;
  buffer: WebGLBuffer;
  sharpTexture: WebGLTexture;
  blurTexture: WebGLTexture;
  sharpTex: WebGLUniformLocation | null;
  blurTex: WebGLUniformLocation | null;
  size: WebGLUniformLocation | null;
  panelOffset: WebGLUniformLocation | null;
  sceneSize: WebGLUniformLocation | null;
  radius: WebGLUniformLocation | null;
  zRadius: WebGLUniformLocation | null;
  refract: WebGLUniformLocation | null;
  chroma: WebGLUniformLocation | null;
  edgeDarkening: WebGLUniformLocation | null;
  spec: WebGLUniformLocation | null;
  fresnel: WebGLUniformLocation | null;
  edgeHL: WebGLUniformLocation | null;
  time: WebGLUniformLocation | null;
  aurora: WebGLUniformLocation | null;
  reveal: WebGLUniformLocation | null;
  settle: WebGLUniformLocation | null;
  lift: WebGLUniformLocation | null;
  ribbonHorizon: WebGLUniformLocation | null;
};

function compileShader(gl: WebGLRenderingContext, type: number, source: string): WebGLShader | null {
  const shader = gl.createShader(type);
  if (!shader) return null;
  gl.shaderSource(shader, source);
  gl.compileShader(shader);
  if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
    gl.deleteShader(shader);
    return null;
  }
  return shader;
}

function createSceneTexture(gl: WebGLRenderingContext): WebGLTexture | null {
  const texture = gl.createTexture();
  if (!texture) return null;
  gl.bindTexture(gl.TEXTURE_2D, texture);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
  return texture;
}

function buildProgram(gl: WebGLRenderingContext): LiquidProgram | null {
  const vertex = compileShader(gl, gl.VERTEX_SHADER, VERTEX_SHADER);
  const fragment = compileShader(gl, gl.FRAGMENT_SHADER, FRAGMENT_SHADER);
  if (!vertex || !fragment) return null;
  const program = gl.createProgram();
  const buffer = gl.createBuffer();
  const sharpTexture = createSceneTexture(gl);
  const blurTexture = createSceneTexture(gl);
  if (!program || !buffer || !sharpTexture || !blurTexture) return null;
  gl.attachShader(program, vertex);
  gl.attachShader(program, fragment);
  gl.linkProgram(program);
  gl.deleteShader(vertex);
  gl.deleteShader(fragment);
  if (!gl.getProgramParameter(program, gl.LINK_STATUS)) return null;

  gl.bindBuffer(gl.ARRAY_BUFFER, buffer);
  gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([-1, -1, 1, -1, -1, 1, 1, 1]), gl.STATIC_DRAW);
  const position = gl.getAttribLocation(program, "a_position");
  gl.enableVertexAttribArray(position);
  gl.vertexAttribPointer(position, 2, gl.FLOAT, false, 0, 0);

  return {
    program,
    buffer,
    sharpTexture,
    blurTexture,
    sharpTex: gl.getUniformLocation(program, "u_sharpTex"),
    blurTex: gl.getUniformLocation(program, "u_blurTex"),
    size: gl.getUniformLocation(program, "u_size"),
    panelOffset: gl.getUniformLocation(program, "u_panelOffset"),
    sceneSize: gl.getUniformLocation(program, "u_sceneSize"),
    radius: gl.getUniformLocation(program, "u_radius"),
    zRadius: gl.getUniformLocation(program, "u_zRadius"),
    refract: gl.getUniformLocation(program, "u_refract"),
    chroma: gl.getUniformLocation(program, "u_chroma"),
    edgeDarkening: gl.getUniformLocation(program, "u_edgeDarkening"),
    spec: gl.getUniformLocation(program, "u_spec"),
    fresnel: gl.getUniformLocation(program, "u_fresnel"),
    edgeHL: gl.getUniformLocation(program, "u_edgeHL"),
    time: gl.getUniformLocation(program, "u_time"),
    aurora: gl.getUniformLocation(program, "u_aurora"),
    reveal: gl.getUniformLocation(program, "u_reveal"),
    settle: gl.getUniformLocation(program, "u_settle"),
    lift: gl.getUniformLocation(program, "u_lift"),
    ribbonHorizon: gl.getUniformLocation(program, "u_ribbonHorizon"),
  };
}

/* aurora shows ONLY while the model is thinking; the static pill and the opened chat stay clean */
function auroraTarget(state: string | undefined): number {
  return state === "thinking" ? 1 : 0;
}

function revealTarget(state: string | undefined): number {
  return state === "collapsed" ? 0 : 1;
}

function settleTarget(state: string | undefined): number {
  return state === "expanded" ? 1 : 0;
}

function approachAt60Hz(current: number, target: number, response: number, deltaMs: number): number {
  const frameScale = Math.max(0, deltaMs) / (1000 / 60);
  return current + (target - current) * (1 - (1 - response) ** frameScale);
}

const EXCLUDE_SELECTOR = '[data-control-ui="dynamic-notification"]';

type EmbeddedImages = ReadonlyMap<string, string>;

function cssImageUrls(value: string): string[] {
  return Array.from(value.matchAll(/url\((["']?)(.*?)\1\)/g), (match) => match[2]?.trim()).filter((url): url is string =>
    Boolean(url && !url.startsWith("data:") && !url.startsWith("#")),
  );
}

function sceneImageUrls(scene: HTMLElement): Set<string> {
  const urls = new Set<string>();
  for (const element of [scene, ...scene.querySelectorAll("*")]) {
    if (element.closest(EXCLUDE_SELECTOR)) continue;
    if (element instanceof HTMLImageElement && element.currentSrc && !element.currentSrc.startsWith("data:")) {
      urls.add(element.currentSrc);
    }
    const computed = getComputedStyle(element);
    for (let index = 0; index < computed.length; index += 1) {
      for (const url of cssImageUrls(computed.getPropertyValue(computed.item(index)))) urls.add(url);
    }
  }
  return urls;
}

function blobDataUrl(blob: Blob): Promise<string | null> {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.addEventListener("load", () => resolve(typeof reader.result === "string" ? reader.result : null), { once: true });
    reader.addEventListener("error", () => resolve(null), { once: true });
    reader.readAsDataURL(blob);
  });
}

async function fetchImageDataUrl(url: string): Promise<string | null> {
  try {
    const resolved = new URL(url, document.baseURI);
    const sameOrigin = resolved.origin === window.location.origin;
    const response = await fetch(resolved, {
      cache: "force-cache",
      credentials: sameOrigin ? "same-origin" : "omit",
      mode: sameOrigin ? "same-origin" : "cors",
    });
    if (!response.ok) return null;
    return blobDataUrl(await response.blob());
  } catch {
    return null;
  }
}

async function embedSceneImages(scene: HTMLElement): Promise<EmbeddedImages | null> {
  const urls = [...sceneImageUrls(scene)];
  const dataUrls = await Promise.all(urls.map(fetchImageDataUrl));
  const images = new Map<string, string>();
  for (let index = 0; index < urls.length; index += 1) {
    const url = urls[index];
    const dataUrl = dataUrls[index];
    if (!url || !dataUrl) return null;
    images.set(url, dataUrl);
  }
  return images;
}

function embedCssImages(value: string, images: EmbeddedImages): string {
  return value.replace(/url\((["']?)(.*?)\1\)/g, (match, _quote: string, url: string) => {
    const embedded = images.get(url.trim());
    return embedded ? `url("${embedded}")` : match;
  });
}

function cloneCanvas(source: HTMLCanvasElement): HTMLImageElement | null {
  try {
    const snapshot = document.createElement("img");
    snapshot.src = source.toDataURL();
    snapshot.setAttribute("style", getComputedStyle(source).cssText);
    return snapshot;
  } catch {
    return null;
  }
}

function computedStyleText(source: Element, images: EmbeddedImages): string {
  const computed = getComputedStyle(source);
  const parts: string[] = [];
  for (let index = 0; index < computed.length; index += 1) {
    const property = computed.item(index);
    parts.push(`${property}: ${embedCssImages(computed.getPropertyValue(property), images)};`);
  }
  return parts.join(" ");
}

function appendClonedChildren(source: Element, target: Element, images: EmbeddedImages): void {
  for (const child of source.childNodes) {
    if (child instanceof Element) {
      const cloned = cloneTree(child, images);
      if (cloned) target.appendChild(cloned);
    } else if (child.nodeType === Node.TEXT_NODE) {
      target.appendChild(child.cloneNode(false));
    }
  }
}

/* Recursive clone with computed styles inlined — the SVG-image sandbox can't reach stylesheets. */
function cloneTree(source: Element, images: EmbeddedImages): Element | null {
  if (source.matches(EXCLUDE_SELECTOR)) return null;

  /* canvases can't paint inside an SVG image: snapshot them into an <img> */
  if (source instanceof HTMLCanvasElement) return cloneCanvas(source);

  const node = source.cloneNode(false);
  if (!(node instanceof Element)) return null;

  node.setAttribute("style", computedStyleText(source, images));
  if (source instanceof HTMLImageElement && node instanceof HTMLImageElement) {
    const embedded = images.get(source.currentSrc);
    if (embedded) node.src = embedded;
    node.removeAttribute("srcset");
    node.removeAttribute("sizes");
  }
  if (source instanceof HTMLSourceElement && source.parentElement instanceof HTMLPictureElement) {
    node.removeAttribute("srcset");
    node.removeAttribute("sizes");
  }
  appendClonedChildren(source, node, images);
  return node;
}

type SceneCapture = { sharp: HTMLCanvasElement; frosted: HTMLCanvasElement };
type SceneCaptureDimensions = {
  width: number;
  height: number;
  rasterWidth: number;
  rasterHeight: number;
};

function scaleCanvas(source: HTMLCanvasElement, width: number, height: number): HTMLCanvasElement | null {
  const step = document.createElement("canvas");
  step.width = width;
  step.height = height;
  const context = step.getContext("2d");
  if (!context) return null;
  context.imageSmoothingEnabled = true;
  context.imageSmoothingQuality = "high";
  context.drawImage(source, 0, 0, width, height);
  return step;
}

function sceneCaptureDimensions(scene: HTMLElement, scale: number): SceneCaptureDimensions {
  const rect = scene.getBoundingClientRect();
  const width = Math.max(1, Math.round(rect.width));
  const height = Math.max(1, Math.round(rect.height));
  return {
    width,
    height,
    rasterWidth: Math.max(1, Math.round(width * scale)),
    rasterHeight: Math.max(1, Math.round(height * scale)),
  };
}

function prepareSceneClone(scene: HTMLElement, dimensions: SceneCaptureDimensions, images: EmbeddedImages): HTMLElement | null {
  const clone = cloneTree(scene, images);
  if (!(clone instanceof HTMLElement)) return null;

  clone.setAttribute("xmlns", "http://www.w3.org/1999/xhtml");
  clone.style.width = `${dimensions.width}px`;
  clone.style.height = `${dimensions.height}px`;
  clone.style.margin = "0";
  clone.style.boxSizing = "border-box";
  return clone;
}

async function decodeSceneImage(clone: HTMLElement, dimensions: SceneCaptureDimensions): Promise<HTMLImageElement | null> {
  const markup = new XMLSerializer().serializeToString(clone);
  const { width, height, rasterWidth, rasterHeight } = dimensions;
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${rasterWidth}" height="${rasterHeight}" viewBox="0 0 ${width} ${height}"><foreignObject width="${width}" height="${height}">${markup}</foreignObject></svg>`;
  const image = new Image();
  image.decoding = "async";
  image.src = `data:image/svg+xml;charset=utf-8,${encodeURIComponent(svg)}`;

  try {
    await image.decode();
    return image;
  } catch {
    return null;
  }
}

function drawSharpScene(image: HTMLImageElement, dimensions: SceneCaptureDimensions): HTMLCanvasElement | null {
  const sharp = document.createElement("canvas");
  sharp.width = dimensions.rasterWidth;
  sharp.height = dimensions.rasterHeight;
  const context = sharp.getContext("2d");
  if (!context) return null;
  context.drawImage(image, 0, 0, sharp.width, sharp.height);
  return sharp;
}

function downsampleForFrost(sharp: HTMLCanvasElement, frost: number): HTMLCanvasElement | null {
  const targetWidth = Math.max(1, Math.round(sharp.width / frost));
  const targetHeight = Math.max(1, Math.round(sharp.height / frost));
  let small: HTMLCanvasElement | null = sharp;
  let stepWidth = sharp.width;
  let stepHeight = sharp.height;

  while (small && stepWidth * 0.5 >= targetWidth) {
    stepWidth = Math.max(targetWidth, Math.round(stepWidth * 0.5));
    stepHeight = Math.max(targetHeight, Math.round(stepHeight * 0.5));
    small = scaleCanvas(small, stepWidth, stepHeight);
  }

  if (small && (small.width !== targetWidth || small.height !== targetHeight)) {
    small = scaleCanvas(small, targetWidth, targetHeight);
  }
  if (!small) return null;

  const bounced = scaleCanvas(small, Math.max(1, Math.round(targetWidth / 2)), Math.max(1, Math.round(targetHeight / 2)));
  return bounced ? (scaleCanvas(bounced, targetWidth, targetHeight) ?? small) : small;
}

function drawFrostedScene(sharp: HTMLCanvasElement, frost: number): HTMLCanvasElement | null {
  const frosted = document.createElement("canvas");
  frosted.width = sharp.width;
  frosted.height = sharp.height;
  const context = frosted.getContext("2d");
  if (!context) return null;

  if (frost <= 1) {
    context.drawImage(sharp, 0, 0);
    return frosted;
  }

  /* Raster-relative downsampling keeps roughly one texel per CSS pixel on high-density screens. */
  const smoothed = downsampleForFrost(sharp, frost);
  if (smoothed) {
    context.imageSmoothingEnabled = true;
    context.imageSmoothingQuality = "high";
    context.drawImage(smoothed, 0, 0, frosted.width, frosted.height);
  } else {
    context.drawImage(sharp, 0, 0);
  }
  return frosted;
}

/* Rasterize the scene (minus islands) → sharp + frosted 2D canvases. The frost pass is a
   downscale/upscale blur (portable approximate gaussian: 2D-context filters are missing in Safari). */
async function captureScene(scene: HTMLElement, scale: number, frost: number): Promise<SceneCapture | null> {
  const images = await embedSceneImages(scene);
  if (!images) return null;
  const dimensions = sceneCaptureDimensions(scene, scale);
  const clone = prepareSceneClone(scene, dimensions, images);
  if (!clone) return null;
  const image = await decodeSceneImage(clone, dimensions);
  if (!image) return null;
  const sharp = drawSharpScene(image, dimensions);
  if (!sharp) return null;
  const frosted = drawFrostedScene(sharp, frost);
  if (!frosted) return null;
  return { sharp, frosted };
}

export function createDynamicNotificationLiquid(canvas: HTMLCanvasElement, options: DynamicNotificationLiquidOptions = {}): () => void {
  const {
    refraction = 0.85,
    chromaticAberration = 0,
    zRadius = 32,
    edgeDarkening = 0.05,
    specular = 0.11,
    fresnel = 0.35,
    edgeHighlight = 0.16,
    frost = 4,
    maxDpr = 2,
  } = options;
  const gl = canvas.getContext("webgl", { alpha: true, premultipliedAlpha: true, antialias: true });
  if (!gl) {
    canvas.dataset.glassFailed = "webgl";
    return () => {
      delete canvas.dataset.glassFailed;
    };
  }

  const closestScene = canvas.closest("[data-dn-scene]");
  const scene = closestScene instanceof HTMLElement ? closestScene : document.body;

  /* Cleanup only deletes GL objects and NEVER loseContext(): a lose()d context can't hand out
     WEBGL_lose_context anymore, so a StrictMode remount on the same canvas could never recover. */
  let contextLost = gl.isContextLost();
  let liquid = contextLost ? null : buildProgram(gl);
  if (!contextLost && !liquid) {
    canvas.dataset.glassFailed = "shader";
    return () => {
      delete canvas.dataset.glassFailed;
    };
  }

  let destroyed = false;
  let intersecting = true;
  let pageVisible = !document.hidden;
  let rafId = 0;
  let dpr = 1;
  let radius = 0;
  const initialState = canvas.parentElement?.dataset.state;
  let aurora = auroraTarget(initialState);
  let reveal = revealTarget(initialState);
  let settle = settleTarget(initialState);
  /* lift sends the dying sheet toward the top on exit; parked high whenever the aurora is off */
  let lift = 1 - aurora;
  let staticFrameDrawn = false;
  /* last successful capture, kept for instant re-upload after a context restore */
  let captured: SceneCapture | null = null;
  let textureFresh = false;
  let captureToken = 0;
  let captureTimer = 0;
  const startedAt = performance.now();
  let previousFrameAt = startedAt;
  const reducedMotionQuery = window.matchMedia("(prefers-reduced-motion: reduce)");

  function reducedMotion(): boolean {
    return reducedMotionQuery.matches || canvas.closest('[data-motion="reduced"]') !== null;
  }

  function targetRadius(host: HTMLElement): number {
    const parsed = Number.parseFloat(getComputedStyle(host).borderTopLeftRadius);
    return Number.isFinite(parsed) ? parsed : 0;
  }

  function targetRibbonHorizon(host: HTMLElement): number {
    const parsed = Number.parseFloat(getComputedStyle(host).getPropertyValue("--dn-ribbon-horizon"));
    return Number.isFinite(parsed) ? Math.min(1, Math.max(0, parsed / 100)) : 0.5;
  }

  /* Runs at the TOP of every draw, never from observers: setting canvas.width clears the buffer,
     so resize and repaint must share one task or the compositor shows a blank frame (flicker). */
  function resize(): void {
    // clientWidth/Height: layout box, immune to the @starting-style scale running at mount.
    dpr = Math.min(window.devicePixelRatio || 1, maxDpr);
    const width = Math.max(1, Math.round(canvas.clientWidth * dpr));
    const height = Math.max(1, Math.round(canvas.clientHeight * dpr));
    if (canvas.width !== width || canvas.height !== height) {
      canvas.width = width;
      canvas.height = height;
    }
  }

  function uploadTexture(): void {
    if (!gl || !liquid || contextLost || !captured) return;
    gl.pixelStorei(gl.UNPACK_PREMULTIPLY_ALPHA_WEBGL, true);
    gl.bindTexture(gl.TEXTURE_2D, liquid.sharpTexture);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, captured.sharp);
    gl.bindTexture(gl.TEXTURE_2D, liquid.blurTexture);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, captured.frosted);
    textureFresh = true;
  }

  function recapture(): void {
    captureToken += 1;
    const token = captureToken;
    /* Supersample beyond dpr so sub-pixel edge optics stay clean without unbounded texture memory. */
    const rect = scene.getBoundingClientRect();
    const supersample = Math.min((window.devicePixelRatio || 1) * 1.5, 3, 4096 / Math.max(rect.width, rect.height, 1));
    void captureScene(scene, Math.max(1, supersample), frost).then((result) => {
      if (destroyed || token !== captureToken) return;
      if (!result) {
        captured = null;
        textureFresh = false;
        delete canvas.dataset.glassReady;
        canvas.dataset.glassFailed = "capture";
        return;
      }
      captured = result;
      delete canvas.dataset.glassFailed;
      uploadTexture();
      invalidate();
    });
  }

  function scheduleRecapture(): void {
    window.clearTimeout(captureTimer);
    captureTimer = window.setTimeout(recapture, 200);
  }

  type MotionTargets = {
    radius: number;
    aurora: number;
    reveal: number;
    settle: number;
    lift: number;
  };

  function advanceMotion(host: HTMLElement, reduced: boolean, deltaMs: number): MotionTargets {
    const state = host.dataset.state;
    const targetAurora = auroraTarget(state);
    const targets = {
      radius: targetRadius(host),
      aurora: targetAurora,
      reveal: revealTarget(state),
      settle: settleTarget(state),
      lift: targetAurora >= 0.5 ? 0 : 1,
    };

    radius = reduced ? targets.radius : approachAt60Hz(radius, targets.radius, 0.25, deltaMs);
    aurora = reduced ? targets.aurora : approachAt60Hz(aurora, targets.aurora, 0.06, deltaMs);
    reveal = reduced ? targets.reveal : approachAt60Hz(reveal, targets.reveal, 0.07, deltaMs);
    settle = reduced ? targets.settle : approachAt60Hz(settle, targets.settle, 0.07, deltaMs);
    /* Keep exit linear so the aurora clears the surface before it collapses. */
    if (reduced) lift = targets.lift;
    else if (targets.lift === 1) lift = Math.min(1, lift + deltaMs * 0.00216);
    else lift = approachAt60Hz(lift, 0, 0.28, deltaMs);

    return targets;
  }

  function shouldAnimate(host: HTMLElement, reduced: boolean, targets: MotionTargets): boolean {
    return (
      !reduced &&
      (host.dataset.state === "thinking" ||
        Math.abs(radius - targets.radius) > 0.05 ||
        Math.abs(aurora - targets.aurora) > 0.002 ||
        Math.abs(reveal - targets.reveal) > 0.002 ||
        Math.abs(settle - targets.settle) > 0.002 ||
        Math.abs(lift - targets.lift) > 0.002)
    );
  }

  function draw(): boolean {
    if (!gl || !liquid || contextLost || !textureFresh) return false;
    const host = canvas.parentElement;
    if (!host) return false;
    resize();
    const hostRect = host.getBoundingClientRect();
    const sceneRect = scene.getBoundingClientRect();
    if (sceneRect.width < 1 || sceneRect.height < 1) return false;

    gl.viewport(0, 0, canvas.width, canvas.height);
    gl.clearColor(0, 0, 0, 0);
    gl.clear(gl.COLOR_BUFFER_BIT);
    // biome-ignore lint/correctness/useHookAtTopLevel: WebGL's useProgram, not a React hook.
    gl.useProgram(liquid.program);
    const reduced = reducedMotion();
    const now = performance.now();
    const deltaMs = Math.min(100, now - previousFrameAt);
    previousFrameAt = now;
    const targets = advanceMotion(host, reduced, deltaMs);

    gl.activeTexture(gl.TEXTURE0);
    gl.bindTexture(gl.TEXTURE_2D, liquid.sharpTexture);
    gl.activeTexture(gl.TEXTURE1);
    gl.bindTexture(gl.TEXTURE_2D, liquid.blurTexture);
    gl.uniform1i(liquid.sharpTex, 0);
    gl.uniform1i(liquid.blurTex, 1);
    gl.uniform2f(liquid.size, Math.max(1, canvas.clientWidth), Math.max(1, canvas.clientHeight));
    gl.uniform2f(liquid.panelOffset, hostRect.left - sceneRect.left, hostRect.top - sceneRect.top);
    gl.uniform2f(liquid.sceneSize, sceneRect.width, sceneRect.height);
    gl.uniform1f(liquid.radius, radius);
    gl.uniform1f(liquid.zRadius, zRadius);
    gl.uniform1f(liquid.refract, refraction);
    gl.uniform1f(liquid.chroma, chromaticAberration);
    gl.uniform1f(liquid.edgeDarkening, edgeDarkening);
    gl.uniform1f(liquid.spec, specular);
    gl.uniform1f(liquid.fresnel, fresnel);
    gl.uniform1f(liquid.edgeHL, edgeHighlight);
    gl.uniform1f(liquid.time, reduced ? 4.2 : (now - startedAt) / 1000);
    gl.uniform1f(liquid.aurora, aurora);
    gl.uniform1f(liquid.reveal, reveal);
    gl.uniform1f(liquid.settle, settle);
    gl.uniform1f(liquid.lift, lift);
    gl.uniform1f(liquid.ribbonHorizon, targetRibbonHorizon(host));
    gl.drawArrays(gl.TRIANGLE_STRIP, 0, 4);
    delete canvas.dataset.glassFailed;
    if (canvas.dataset.glassReady !== "true") canvas.dataset.glassReady = "true";
    return shouldAnimate(host, reduced, targets);
  }

  function visible(): boolean {
    return intersecting && pageVisible;
  }

  function tick(): void {
    rafId = 0;
    if (destroyed || !visible() || contextLost) return;
    const keepAnimating = draw();
    if (!keepAnimating) {
      staticFrameDrawn = true;
      return;
    }
    staticFrameDrawn = false;
    rafId = requestAnimationFrame(tick);
  }

  function invalidate(): void {
    staticFrameDrawn = false;
    if (destroyed || !visible() || contextLost || rafId !== 0) return;
    rafId = requestAnimationFrame(tick);
  }

  function handleVisibility(): void {
    pageVisible = !document.hidden;
    invalidate();
  }

  function handleContextLost(event: Event): void {
    event.preventDefault();
    contextLost = true;
    textureFresh = false;
    delete canvas.dataset.glassReady;
    canvas.dataset.glassFailed = "context";
    if (rafId !== 0) cancelAnimationFrame(rafId);
    rafId = 0;
  }

  function handleContextRestored(): void {
    if (!gl) return;
    contextLost = false;
    liquid = buildProgram(gl);
    if (!liquid) {
      canvas.dataset.glassFailed = "shader";
      return;
    }
    uploadTexture();
    invalidate();
  }

  /* observers only INVALIDATE — the actual buffer resize happens inside draw() (see resize) */
  const resizeObserver = new ResizeObserver(() => {
    invalidate();
  });
  resizeObserver.observe(canvas);

  /* the scene resizing changes the capture geometry, not just the viewport */
  const sceneResizeObserver = new ResizeObserver(() => {
    scheduleRecapture();
  });
  sceneResizeObserver.observe(scene);

  /* re-rasterize when the backdrop actually changes — mutations inside any island are the morph
     itself animating and must NOT trigger captures (the island is excluded from the raster anyway) */
  const sceneMutationObserver = new MutationObserver((mutations) => {
    for (const mutation of mutations) {
      const target = mutation.target;
      const element = target instanceof Element ? target : target.parentElement;
      if (element?.closest(EXCLUDE_SELECTOR)) continue;
      scheduleRecapture();
      return;
    }
  });
  sceneMutationObserver.observe(scene, { attributes: true, characterData: true, childList: true, subtree: true });

  const intersectionObserver = new IntersectionObserver(
    (entries) => {
      for (const entry of entries) intersecting = entry.isIntersecting;
      invalidate();
    },
    { rootMargin: "64px" },
  );
  intersectionObserver.observe(canvas);

  const motionObserver = new MutationObserver(() => {
    if (!staticFrameDrawn || !reducedMotion()) invalidate();
  });
  motionObserver.observe(document.documentElement, { attributes: true, attributeFilter: ["data-motion"] });

  function handleMotionPreference(): void {
    invalidate();
  }

  document.addEventListener("visibilitychange", handleVisibility);
  reducedMotionQuery.addEventListener("change", handleMotionPreference);
  canvas.addEventListener("webglcontextlost", handleContextLost);
  canvas.addEventListener("webglcontextrestored", handleContextRestored);

  recapture();
  invalidate();

  return () => {
    destroyed = true;
    if (rafId !== 0) cancelAnimationFrame(rafId);
    window.clearTimeout(captureTimer);
    resizeObserver.disconnect();
    sceneResizeObserver.disconnect();
    sceneMutationObserver.disconnect();
    intersectionObserver.disconnect();
    motionObserver.disconnect();
    document.removeEventListener("visibilitychange", handleVisibility);
    reducedMotionQuery.removeEventListener("change", handleMotionPreference);
    canvas.removeEventListener("webglcontextlost", handleContextLost);
    canvas.removeEventListener("webglcontextrestored", handleContextRestored);
    delete canvas.dataset.glassReady;
    delete canvas.dataset.glassFailed;
    if (liquid && !gl.isContextLost()) {
      gl.deleteProgram(liquid.program);
      gl.deleteBuffer(liquid.buffer);
      gl.deleteTexture(liquid.sharpTexture);
      gl.deleteTexture(liquid.blurTexture);
    }
    liquid = null;
    captured = null;
  };
}

export const DYNAMIC_NOTIFICATION_SIRI_WAVE_GLSL = /* glsl */ `
const float SIRI_PI = 3.14159265359;
const float SIRI_AMPLITUDE = 0.32;
const float SIRI_FREQUENCY = 1.1;
const float SIRI_ABERRATION_FREQUENCY = 1.0;
const float SIRI_SPEED = 2.4;
const float SIRI_WAVE_SCALE = 0.6;
const float SIRI_ABERRATION = 2.6;
const float SIRI_THICKNESS = 3.0;
const float SIRI_INTENSITY = 2.0;
const float SIRI_FALLOFF = 1.7;
const float SIRI_EDGE_MASK = 0.4;
const float SIRI_BAND_FILL = 30000.0;
const float SIRI_BAND_THICKNESS = 0.08;
const float SIRI_SOFTNESS = 2.5;
const float SIRI_LOW_AMPLITUDE = 6.0;
const float SIRI_LOW_INTENSITY = 1.5;
const float SIRI_MID_ABERRATION = 0.8;
const float SIRI_MID_ABERRATION_AMPLITUDE = 0.05;
const float SIRI_MID_SOFTNESS = 0.4;
const float SIRI_HIGH_ABERRATION = 0.5;
const float SIRI_HIGH_ABERRATION_AMPLITUDE = 0.06;

vec3 siriSpectrum(int strand) {
  float x = float(strand);
  return clamp(vec3(abs(x - 3.0) - 1.0, 2.0 - abs(x - 2.0), 2.0 - abs(x - 4.0)), 0.0, 1.0);
}

vec3 dynamicNotificationSiriWave(vec2 uv, vec2 resolution, float time, float horizon, float lift) {
  float aspect = resolution.x / max(resolution.y, 1.0);
  vec2 p = vec2((uv.x * 2.0 - 1.0) * aspect, (uv.y - horizon + lift * 0.55) * 2.0);
  float screenY = p.y;
  p /= max(SIRI_WAVE_SCALE, 0.1);

  float low = clamp(0.45 + 0.45 * sin(time * 0.8) * sin(time * 0.37 + 1.0), 0.0, 1.0);
  float mid = clamp(0.40 + 0.40 * sin(time * 1.7 + 2.0) * sin(time * 0.53), 0.0, 1.0);
  float high = clamp(0.30 + 0.30 * sin(time * 2.9 + 4.0) * sin(time * 0.71 + 2.0), 0.0, 1.0);
  float drift = mod(time, 20.0 * SIRI_PI) * SIRI_SPEED;

  float horizontalPosition = uv.x * 2.0 - 1.0;
  float envelope = cos(SIRI_PI * 0.5 * min(abs(0.9 * horizontalPosition), 1.0));
  envelope *= envelope;

  float primaryAmplitude = SIRI_AMPLITUDE + 0.01 * low * SIRI_LOW_AMPLITUDE;
  float strandAmplitude = primaryAmplitude + mid * SIRI_MID_ABERRATION_AMPLITUDE + high * SIRI_HIGH_ABERRATION_AMPLITUDE;
  float aberration = SIRI_ABERRATION + mid * SIRI_MID_ABERRATION + high * SIRI_HIGH_ABERRATION;
  float thickness = 0.01 * SIRI_THICKNESS;
  float intensity = 0.01 * (SIRI_INTENSITY + low * SIRI_LOW_INTENSITY);
  float softness = 0.01 * max(0.0, SIRI_SOFTNESS + mid * SIRI_MID_SOFTNESS);
  float primaryY = primaryAmplitude * envelope * sin(p.x * SIRI_FREQUENCY + drift);
  float bandAmount = 1e-4 * SIRI_BAND_FILL * intensity;

  vec3 numerator = vec3(0.0);
  vec3 denominator = vec3(0.0);
  for (int strand = 0; strand < 4; strand++) {
    vec3 hue = siriSpectrum(strand);
    denominator += hue;
    float phase = mix(-aberration, aberration, float(strand) / 3.0);
    float strandY = strandAmplitude * envelope * sin(p.x * SIRI_ABERRATION_FREQUENCY + drift + phase);
    float distanceToStrand = abs(p.y - strandY);
    float line = intensity / (sqrt(distanceToStrand * distanceToStrand + softness * softness) + thickness);
    float bandLow = min(primaryY, strandY);
    float bandHigh = max(primaryY, strandY);
    float distanceToBand = max(0.0, max(p.y - bandHigh, bandLow - p.y));
    float band = bandAmount / (distanceToBand + SIRI_BAND_THICKNESS);
    numerator += hue * (line + band);
  }

  vec3 color = numerator / max(denominator, vec3(0.0001));
  float primaryDistance = abs(p.y - primaryY);
  color += 0.5 * intensity / (sqrt(primaryDistance * primaryDistance + softness * softness) + thickness);
  color = pow(max(color, 0.0), vec3(1.5));

  float edgeFadePosition = clamp((abs(screenY) - 1.0) / -SIRI_EDGE_MASK, 0.0, 1.0);
  float edgeFade = edgeFadePosition * edgeFadePosition * (3.0 - 2.0 * edgeFadePosition);
  color *= edgeFade * exp(-pow(horizontalPosition * SIRI_FALLOFF, 2.0));
  return color;
}
`;

/*
 * DynamicNotification morph + text choreography, token-driven (motion kill-switch collapses to 0).
 * Geometry rides a real damped-spring linear() curve (slight overshoot, no mechanical ease); the
 * pill face and bubble content cross-fade with blur on offset schedules so nothing pops or jumps.
 * Island interpolates pill→bubble size (interpolate-size: allow-keywords upgrades height:auto
 * interpolation where supported; elsewhere height snaps and the cross-fade still reads).
 * Reads the shared --duration-* and --ease-* tokens.
 */

@keyframes dn-word-in {
  from {
    opacity: 0;
    filter: blur(8px);
    translate: 0 0.4em;
  }
}

@keyframes dn-indicator-breathe {
  0%,
  100% {
    scale: 1;
    opacity: 0.85;
  }
  50% {
    scale: 1.35;
    opacity: 1;
  }
}

/* Registered ink stops (glass/liquid fallback material): background-image itself can't
   interpolate, but registered custom properties can — transitioning these colors AND their stop
   positions morphs the gradient from a SOLID black pill face into the bubble fade.
   Initial values = the collapsed pill (full black); thinking and expanded override them below. */
@property --dn-ink-mid {
  syntax: "<color>";
  inherits: false;
  initial-value: oklch(0 0 0 / 0.97);
}
@property --dn-ink-low {
  syntax: "<color>";
  inherits: false;
  initial-value: oklch(0 0 0 / 0.97);
}
@property --dn-ink-tail {
  syntax: "<color>";
  inherits: false;
  initial-value: oklch(0 0 0 / 0.97);
}
/* where each stop sits, so thinking (fade opening high, 10% black tail) and expanded (opaque
   plateau down to 70%, then a shallow fade to a 0.4 floor) are the SAME gradient at two settings */
@property --dn-ink-plateau {
  syntax: "<percentage>";
  inherits: false;
  initial-value: 100%;
}
@property --dn-ink-mid-stop {
  syntax: "<percentage>";
  inherits: false;
  initial-value: 100%;
}
@property --dn-ink-low-stop {
  syntax: "<percentage>";
  inherits: false;
  initial-value: 100%;
}
@property --dn-ink-tail-stop {
  syntax: "<percentage>";
  inherits: false;
  initial-value: 100%;
}

@layer components {
  /* ---- island geometry morph ------------------------------------------------------------- */
  :where([data-control-ui="dynamic-notification"][data-slot="island"]) {
    /* geometry knobs — retune via inline style or className */
    --dn-collapsed-width: 8.5rem;
    --dn-collapsed-height: 2.5rem;
    --dn-expanded-width: 22.5rem;
    --dn-expanded-radius: 1.65rem;
    --dn-ribbon-horizon: 50%;
    /* motion knobs — damped springs sampled into linear() (ζ=0.72 geometry, ζ=0.85 content) */
    --dn-morph-duration: calc(var(--duration-slow) * 2);
    --dn-word-stagger: 42ms;
    --dn-ease-spring: linear(
      0, 0.0568 3.85%, 0.1888 7.69%, 0.351 11.54%, 0.5142 15.38%, 0.6608 19.23%,
      0.7824 23.08%, 0.8767 26.92%, 0.9449 30.77%, 0.9908 34.62%, 1.0187 38.46%,
      1.0332 42.31%, 1.0382 46.15%, 1.0372 50%, 1.0327 53.85%, 1.0266 57.69%,
      1.0203 61.54%, 1.0145 65.38%, 1.0095 69.23%, 1.0056 73.08%, 1.0027 76.92%,
      1.0008 80.77%, 0.9995 84.62%, 0.9988 88.46%, 0.9986 92.31%, 0.9985 96.15%, 1
    );
    --dn-ease-glide: linear(
      0, 0.0553 4.55%, 0.1795 9.09%, 0.328 13.64%, 0.4745 18.18%, 0.6054 22.73%,
      0.7148 27.27%, 0.8017 31.82%, 0.868 36.36%, 0.9166 40.91%, 0.9509 45.45%,
      0.9741 50%, 0.9891 54.55%, 0.9982 59.09%, 1.0032 63.64%, 1.0056 68.18%,
      1.0063 72.73%, 1.006 77.27%, 1.0053 81.82%, 1.0044 86.36%, 1.0034 90.91%,
      1.0026 95.45%, 1
    );
    interpolate-size: allow-keywords;
    width: var(--dn-collapsed-width);
    height: var(--dn-collapsed-height);
    border-radius: calc(var(--dn-collapsed-height) / 2);
    opacity: 1;
    scale: 1;
    translate: 0 0;
    filter: blur(0);
    transition:
      width var(--dn-morph-duration) var(--dn-ease-spring),
      height var(--dn-morph-duration) var(--dn-ease-spring),
      border-radius var(--dn-morph-duration) var(--dn-ease-spring),
      box-shadow var(--dn-morph-duration) var(--ease-standard),
      opacity var(--duration-slow) var(--ease-emphasized),
      scale var(--dn-morph-duration) var(--dn-ease-spring),
      translate var(--dn-morph-duration) var(--dn-ease-spring),
      filter var(--duration-slow) var(--ease-emphasized),
      --dn-ink-mid var(--dn-morph-duration) var(--dn-ease-glide),
      --dn-ink-low var(--dn-morph-duration) var(--dn-ease-glide),
      --dn-ink-tail var(--dn-morph-duration) var(--dn-ease-glide),
      --dn-ink-plateau var(--dn-morph-duration) var(--dn-ease-glide),
      --dn-ink-mid-stop var(--dn-morph-duration) var(--dn-ease-glide),
      --dn-ink-low-stop var(--dn-morph-duration) var(--dn-ease-glide),
      --dn-ink-tail-stop var(--dn-morph-duration) var(--dn-ease-glide);
  }

  /* arrival pop: the island springs in from the notch when it mounts */
  @starting-style {
    :where([data-control-ui="dynamic-notification"][data-slot="island"]) {
      opacity: 0;
      scale: 0.85;
      translate: 0 -0.4rem;
      filter: blur(10px);
    }
  }

  /* thinking = the model is answering: an intermediate rounded blob, faces hidden, aurora animating */
  :where([data-control-ui="dynamic-notification"][data-slot="island"])[data-state="thinking"] {
    width: min(var(--dn-thinking-width, 10rem), 100%);
    height: var(--dn-thinking-height, 5.75rem);
    border-radius: var(--dn-thinking-radius, 2.75rem);
    /* The fade is centred on the same horizon as the spectral ribbon. */
    --dn-ink-plateau: calc(var(--dn-ribbon-horizon) - 10%);
    --dn-ink-mid-stop: calc(var(--dn-ribbon-horizon) - 3%);
    --dn-ink-low-stop: calc(var(--dn-ribbon-horizon) + 3%);
    --dn-ink-tail-stop: calc(var(--dn-ribbon-horizon) + 10%);
    --dn-ink-mid: oklch(0 0 0 / 0.72);
    --dn-ink-low: oklch(0 0 0 / 0.3);
    --dn-ink-tail: oklch(0 0 0 / 0.1);
  }

  :where([data-control-ui="dynamic-notification"][data-slot="island"])[data-state="expanded"] {
    width: min(var(--dn-expanded-width), 100%);
    height: auto;
    border-radius: var(--dn-expanded-radius);
    /* the bubble carries the reply field and submit button in its bottom third, so its ink never
       runs out: opaque plateau down to 70%, then a shallow fade to a 0.4 floor. Enough backdrop to
       keep the controls legible, translucent enough that the wallpaper still shows through. */
    --dn-ink-plateau: 70%;
    --dn-ink-mid-stop: 82%;
    --dn-ink-low-stop: 92%;
    --dn-ink-tail-stop: 100%;
    --dn-ink-mid: oklch(0 0 0 / 0.78);
    --dn-ink-low: oklch(0 0 0 / 0.55);
    --dn-ink-tail: oklch(0 0 0 / 0.4);
  }

  /* ---- pill face <-> bubble content cross-fade -------------------------------------------- */
  /* focus/a11y gating lives on the inert attribute (stamped by React); CSS only paints the cross-fade */

  /* base = collapsed face; it returns AFTER the geometry has mostly settled back (delayed) */
  :where([data-control-ui="dynamic-notification"][data-slot="pill"]) {
    opacity: 1;
    filter: blur(0);
    scale: 1;
    transition:
      opacity var(--duration-base) var(--ease-standard) calc(var(--duration-slow) * 0.55),
      filter var(--duration-base) var(--ease-standard) calc(var(--duration-slow) * 0.55),
      scale var(--duration-base) var(--ease-emphasized) calc(var(--duration-slow) * 0.55);
  }

  /* opening (thinking or expanded): pill dissolves immediately and fast, clearing the stage */
  :where([data-control-ui="dynamic-notification"][data-slot="island"]:not([data-state="collapsed"]))
    :where([data-control-ui="dynamic-notification"][data-slot="pill"]) {
    opacity: 0;
    filter: blur(6px);
    scale: 0.8;
    pointer-events: none;
    transition-duration: var(--duration-fast);
    transition-delay: 0s;
  }

  /* base = expanded content; it unfurls from the pill (origin top) on the glide spring */
  :where([data-control-ui="dynamic-notification"][data-slot="content"]) {
    opacity: 1;
    filter: blur(0);
    translate: 0 0;
    scale: 1;
    transform-origin: 50% 0%;
    transition:
      opacity calc(var(--duration-slow) * 1.4) var(--ease-emphasized) calc(var(--duration-fast) * 0.6),
      filter calc(var(--duration-slow) * 1.4) var(--ease-emphasized) calc(var(--duration-fast) * 0.6),
      translate var(--dn-morph-duration) var(--dn-ease-glide) calc(var(--duration-fast) * 0.6),
      scale var(--dn-morph-duration) var(--dn-ease-glide) calc(var(--duration-fast) * 0.6);
  }

  /* collapsed or thinking: content stays folded into the island, quick and undelayed */
  :where([data-control-ui="dynamic-notification"][data-slot="island"]:not([data-state="expanded"]))
    :where([data-control-ui="dynamic-notification"][data-slot="content"]) {
    opacity: 0;
    filter: blur(10px);
    translate: 0 -0.5rem;
    scale: 0.94;
    transition:
      opacity var(--duration-base) var(--ease-standard),
      filter var(--duration-base) var(--ease-standard),
      translate var(--duration-base) var(--ease-standard),
      scale var(--duration-base) var(--ease-standard);
  }

  /* ---- word cascade (Apple keynote text reveal) -------------------------------------------- */
  :where([data-control-ui="dynamic-notification"][data-slot="message"]) [data-control-ui="dynamic-notification"][data-slot="word"] {
    display: inline-block;
  }

  /* scoped to the expanded state so the cascade fires at REVEAL time — including after a
     thinking phase (the animation starts when the selector begins matching, not at mount) */
  :where([data-control-ui="dynamic-notification"][data-slot="island"][data-state="expanded"])
    :where([data-control-ui="dynamic-notification"][data-slot="message"])
    [data-control-ui="dynamic-notification"][data-slot="word"] {
    animation: dn-word-in calc(var(--duration-slow) * 1.8) var(--dn-ease-glide, var(--ease-emphasized)) both;
    /* constant offset lets the bubble land first; per-word step gated by --dn-word-stagger */
    animation-delay: calc(var(--duration-base) * 0.8 + var(--dn-word-index, 0) * var(--dn-word-stagger, 40ms));
  }

  /* ---- Siri indicator orb ------------------------------------------------------------------ */
  :where([data-control-ui="dynamic-notification"][data-slot="indicator"]) {
    background:
      radial-gradient(circle at 30% 30%, oklch(0.85 0.1 210 / 0.9), transparent 60%),
      conic-gradient(from 210deg, oklch(0.62 0.19 25), oklch(0.75 0.15 70), oklch(0.7 0.17 250), oklch(0.62 0.19 25));
    box-shadow: 0 0 8px oklch(0.7 0.17 250 / 0.55);
    animation: dn-indicator-breathe calc(var(--duration-slow) * 5) var(--ease-standard) infinite;
  }

  /* infinite animation ignores the 0ms token collapse — explicit opt-out, mirroring shimmer-text.
     Word stagger is a raw ms knob, so it collapses here too (durations already collapse via tokens). */
  @media (prefers-reduced-motion: reduce) {
    :where([data-control-ui="dynamic-notification"][data-slot="island"]) {
      --dn-word-stagger: 0ms;
    }
    :where([data-control-ui="dynamic-notification"][data-slot="indicator"]) {
      animation: none;
    }
  }
  :where([data-motion="reduced"]) :where([data-control-ui="dynamic-notification"][data-slot="island"]) {
    --dn-word-stagger: 0ms;
  }
  :where([data-motion="reduced"]) :where([data-control-ui="dynamic-notification"][data-slot="indicator"]) {
    animation: none;
  }

  /* ---- glass variant material (CSS fallback; the WebGL canvas paints over it) -------------- */
  /* collapsed = solid black pill (ink stops at their registered initial values); expanded =
     true black -> transparent, reached by TRANSITIONING the registered stops (see @property).
     Plateau curve, not an even fade: solid across the top 40%, transparent by 90% — keeps a
     dark backing behind the mid-height aurora sheet */
  :where([data-control-ui="dynamic-notification"][data-slot="island"])[data-variant="glass"] {
    background: linear-gradient(
      to bottom,
      oklch(0 0 0 / 0.97) 0%,
      oklch(0 0 0 / 0.97) var(--dn-ink-plateau),
      var(--dn-ink-mid) var(--dn-ink-mid-stop),
      var(--dn-ink-low) var(--dn-ink-low-stop),
      var(--dn-ink-tail) var(--dn-ink-tail-stop),
      var(--dn-ink-tail) 100%
    );
    backdrop-filter: blur(4px) saturate(1.4);
  }

  /* ---- liquid variant fallback (WebGL replaces it after the first complete frame) ------------- */
  :where([data-control-ui="dynamic-notification"][data-slot="island"])[data-variant="liquid"] {
    background: linear-gradient(
      to bottom,
      oklch(0 0 0 / 0.97) 0%,
      oklch(0 0 0 / 0.97) var(--dn-ink-plateau),
      var(--dn-ink-mid) var(--dn-ink-mid-stop),
      var(--dn-ink-low) var(--dn-ink-low-stop),
      var(--dn-ink-tail) var(--dn-ink-tail-stop),
      var(--dn-ink-tail) 100%
    );
  }

  :where(
      [data-control-ui="dynamic-notification"][data-slot="island"][data-variant="glass"],
      [data-control-ui="dynamic-notification"][data-slot="island"][data-variant="liquid"]
    ):has([data-glass-ready="true"]) {
    background: transparent;
  }

  /* WebGL layers fade in only after their first painted frame (liquid-metal pattern, no flash) */
  :where(
      [data-control-ui="dynamic-notification"][data-slot="glass"],
      [data-control-ui="dynamic-notification"][data-slot="liquid"]
    ) {
    opacity: 0;
    transition: opacity var(--duration-base) var(--ease-standard);
  }
  :where(
      [data-control-ui="dynamic-notification"][data-slot="glass"],
      [data-control-ui="dynamic-notification"][data-slot="liquid"]
    )[data-glass-ready="true"] {
    opacity: 1;
  }
}

"use client";

import type { ChangeEvent, ComponentProps, CSSProperties, KeyboardEvent, MouseEvent, SubmitEvent } from "react";
import { createContext, useContext, useEffect, useId, useRef } from "react";

import type { DynamicNotificationProps, DynamicNotificationState, DynamicNotificationVariant } from "@/components/control-ui/contracts";
import { createDynamicNotificationGlass } from "@/components/control-ui/dynamic-notification-glass";
import { createDynamicNotificationLiquid } from "@/components/control-ui/dynamic-notification-liquid";
import { useDynamicNotification } from "@/components/control-ui/hooks/use-dynamic-notification";
import { cn } from "@/components/control-ui/lib/cn";
import { skinSlot } from "@/components/control-ui/skin";
import { Button } from "@/components/control-ui/ui/button";

/*
 * Dynamic Island-style AI notification: a resident pill that receives a message and morphs into a
 * reply bubble on press. Anatomy is variant-agnostic; `variant` only swaps the island MATERIAL:
 * "surface" rides the popover token set (clean, theme-driven), "glass" is the backdrop-blurred black→glass
 * gradient — CSS fallback always, <DynamicNotificationGlass> upgrades it to the WebGL material —
 * and "liquid" uses an unfiltered CSS fallback while <DynamicNotificationLiquid> rasterizes the
 * scene for WebGL transmission, edge refraction, and highlights.
 * Lifecycle: collapsed → "thinking" (open + loading: intermediate blob, aurora animating while the
 * model answers) → expanded (answer + reply). Morph + text choreography live in
 * dynamic-notification.css (token-driven, kill-switch flattens).
 */

type DynamicNotificationContextValue = ReturnType<typeof useDynamicNotification> & {
  state: DynamicNotificationState;
  variant: DynamicNotificationVariant;
  contentId: string;
};

const DynamicNotificationContext = createContext<DynamicNotificationContextValue | null>(null);

const materialClassesByVariant = {
  surface: "bg-popover text-popover-foreground shadow-pop ring-1 ring-inset ring-border backdrop-blur-[var(--backdrop-blur-popover)]",
  glass: "text-white shadow-pop ring-1 ring-inset ring-white/12",
  liquid: "text-white text-shadow-[0_1px_2px_oklch(0_0_0/0.25)]",
} satisfies Record<DynamicNotificationVariant, string>;

function resolveNotificationState(open: boolean, loading: boolean): DynamicNotificationState {
  if (!open) return "collapsed";
  if (loading) return "thinking";
  return "expanded";
}

export function useDynamicNotificationContext() {
  const context = useContext(DynamicNotificationContext);
  if (!context) throw new Error("DynamicNotification compound components must be rendered inside <DynamicNotification>.");
  return context;
}

export function DynamicNotification({
  open,
  defaultOpen,
  onOpenChange,
  loading = false,
  replyValue,
  defaultReplyValue,
  onReplyValueChange,
  onReply,
  variant = "surface",
  disabled = false,
  className,
  children,
  ...props
}: DynamicNotificationProps) {
  const notification = useDynamicNotification({
    open,
    defaultOpen,
    onOpenChange,
    replyValue,
    defaultReplyValue,
    onReplyValueChange,
    onReply,
    disabled,
  });
  const contentId = useId();
  const state = resolveNotificationState(notification.open, loading);

  return (
    <DynamicNotificationContext.Provider value={{ ...notification, state, variant, contentId }}>
      <div
        data-control-ui="dynamic-notification"
        data-slot="root"
        data-state={state}
        data-variant={variant}
        className={cn("relative flex w-full justify-center", skinSlot("dynamic-notification", "root", { state, variant }), className)}
        {...props}
      >
        {children}
      </div>
    </DynamicNotificationContext.Provider>
  );
}

export type DynamicNotificationIslandProps = ComponentProps<"section">;

export function DynamicNotificationIsland({ className, onKeyDown, ...props }: DynamicNotificationIslandProps) {
  const context = useDynamicNotificationContext();
  const materialClasses = materialClassesByVariant[context.variant];

  function handleKeyDown(event: KeyboardEvent<HTMLElement>) {
    onKeyDown?.(event);
    if (event.defaultPrevented) return;
    if (event.key === "Escape" && context.open) {
      context.setOpen(false, "escape-key", event.nativeEvent, event.currentTarget);
    }
  }

  return (
    <section
      aria-label="Assistant notification"
      aria-busy={context.state === "thinking" || undefined}
      data-control-ui="dynamic-notification"
      data-slot="island"
      data-state={context.state}
      data-variant={context.variant}
      onKeyDown={handleKeyDown}
      className={cn(
        "relative isolate overflow-hidden outline-none",
        // glass/liquid MATERIALS are painted by dynamic-notification.css (fallbacks) + the optional WebGL canvases.
        materialClasses,
        skinSlot("dynamic-notification", "island", { state: context.state, variant: context.variant }),
        className,
      )}
      {...props}
    />
  );
}

export type DynamicNotificationGlassProps = ComponentProps<"canvas">;

/** WebGL liquid-glass layer for variant="glass"; render nothing else changes — CSS fallback stays underneath. */
export function DynamicNotificationGlass({ className, ...props }: DynamicNotificationGlassProps) {
  const canvasRef = useRef<HTMLCanvasElement | null>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    return createDynamicNotificationGlass(canvas);
  }, []);

  return (
    <canvas
      ref={canvasRef}
      aria-hidden="true"
      tabIndex={-1}
      data-control-ui="dynamic-notification"
      data-slot="glass"
      className={cn("pointer-events-none absolute inset-0 -z-10 size-full", skinSlot("dynamic-notification", "glass", {}), className)}
      {...props}
    />
  );
}

export type DynamicNotificationLiquidProps = ComponentProps<"canvas">;

/** WebGL transmits the nearest scene through the surface while keeping distortion concentrated at its edge. */
export function DynamicNotificationLiquid({ className, ...props }: DynamicNotificationLiquidProps) {
  const canvasRef = useRef<HTMLCanvasElement | null>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    return createDynamicNotificationLiquid(canvas);
  }, []);

  return (
    <canvas
      ref={canvasRef}
      aria-hidden="true"
      tabIndex={-1}
      data-control-ui="dynamic-notification"
      data-slot="liquid"
      className={cn("pointer-events-none absolute inset-0 -z-10 size-full", skinSlot("dynamic-notification", "liquid", {}), className)}
      {...props}
    />
  );
}

export type DynamicNotificationPillProps = ComponentProps<"button">;

/** Collapsed face; pressing it expands the bubble ("tap to answer"). */
export function DynamicNotificationPill({ className, children, onClick, ...props }: DynamicNotificationPillProps) {
  const context = useDynamicNotificationContext();

  function handleClick(event: MouseEvent<HTMLButtonElement>) {
    onClick?.(event);
    if (event.defaultPrevented) return;
    context.setOpen(true, "trigger-press", event.nativeEvent, event.currentTarget);
  }

  return (
    <button
      type="button"
      aria-expanded={context.open}
      aria-controls={context.contentId}
      // inert (not CSS visibility) gates focus/a11y: it lands with the React commit, so tab order is
      // correct mid-morph (visibility's discrete transition only flips halfway through).
      inert={context.open}
      data-control-ui="dynamic-notification"
      data-slot="pill"
      onClick={handleClick}
      disabled={context.disabled}
      className={cn(
        "absolute inset-0 flex cursor-pointer items-center justify-center gap-2 px-4 text-caption font-medium outline-none",
        "focus-visible:ring-2 focus-visible:ring-inset focus-visible:ring-current/25",
        skinSlot("dynamic-notification", "pill", {}),
        className,
      )}
      {...props}
    >
      {children}
    </button>
  );
}

