      data-slot="reply-submit"
      type="submit"
      variant="solid"
      size="lg"
      iconOnly
      shape="circle"
      aria-label="Send reply"
      disabled={disabled ?? !context.canSubmit}
      className={cn("shrink-0", skinSlot("dynamic-notification", "reply-submit", {}), className)}
      {...props}
